import React, { useEffect, useState } from "react";
import Layout from "./../../components/shared/Layout/Layout";
import { useSelector } from "react-redux";
import API from "../../services/API";
import moment from "moment";

const OrganisationPage = () => {
  const { user } = useSelector((state) => state.auth);
  const [orgs, setOrgs] = useState([]);
  const [camps, setCamps] = useState([]);
  const [search, setSearch] = useState("");

  const getOrgs = async () => {
    try {
      if (user?.role === "donar") {
        const { data } = await API.get("/inventory/get-all-organisations");
        if (data?.success) setOrgs(data?.organisations);
      }
      if (user?.role === "hospital") {
        const { data } = await API.get(
          "/inventory/get-orgnaisation-for-hospital",
        );
        if (data?.success) setOrgs(data?.organisations);
      }
    } catch (error) {
      console.log(error);
    }
  };

  const getCamps = async () => {
    try {
      const { data } = await API.get("/camp/get-all-camps");
      if (data?.success) setCamps(data?.camps);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    getOrgs();
    getCamps();
  }, [user]);

  const filteredOrgs = orgs.filter(
    (org) =>
      org.organisationName?.toLowerCase().includes(search.toLowerCase()) ||
      org.address?.toLowerCase().includes(search.toLowerCase()),
  );

  const getCampsForOrg = (orgId) =>
    camps.filter((c) => (c.organisation?._id || c.organisation) === orgId);

  return (
    <Layout>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Syne:wght@600;700;800&family=DM+Sans:wght@300;400;500&display=swap');
        .org-page { font-family: 'DM Sans', sans-serif; }
        .org-title { font-family: 'Syne', sans-serif; font-size: 26px; font-weight: 700; color: #fff; margin-bottom: 4px; }
        .org-title span { background: linear-gradient(90deg, #c084fc, #f472b6); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
        .org-subtitle { font-size: 14px; color: rgba(255,255,255,0.4); margin-bottom: 28px; }
        .org-search { width: 100%; max-width: 400px; padding: 12px 16px; background: rgba(255,255,255,0.05); border: 1.5px solid rgba(255,255,255,0.1); border-radius: 12px; color: #fff; font-size: 14px; font-family: 'DM Sans', sans-serif; outline: none; transition: all 0.2s; margin-bottom: 28px; display: block; }
        .org-search:focus { border-color: #a855f7; background: rgba(168,85,247,0.08); }
        .org-search::placeholder { color: rgba(255,255,255,0.2); }
        .all-camps-section { margin-bottom: 36px; }
        .section-title { font-family: 'Syne', sans-serif; font-size: 17px; font-weight: 700; color: #fff; margin-bottom: 6px; }
        .section-sub { font-size: 13px; color: rgba(255,255,255,0.35); margin-bottom: 16px; }
        .camps-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(270px, 1fr)); gap: 14px; }
        .camp-card { background: rgba(168,85,247,0.07); border: 1px solid rgba(168,85,247,0.2); border-radius: 16px; padding: 18px; transition: all 0.2s; }
        .camp-card:hover { border-color: rgba(168,85,247,0.4); transform: translateY(-2px); box-shadow: 0 6px 20px rgba(0,0,0,0.25); }
        .camp-card-top { display: flex; align-items: center; gap: 10px; margin-bottom: 10px; }
        .camp-icon { font-size: 20px; }
        .camp-name { font-family: 'Syne', sans-serif; font-size: 14px; font-weight: 700; color: #fff; }
        .camp-active-badge { display: inline-block; padding: 2px 8px; border-radius: 6px; font-size: 10px; font-weight: 600; background: rgba(34,197,94,0.15); color: #4ade80; margin-left: 6px; }
        .camp-detail { font-size: 12px; color: rgba(255,255,255,0.45); margin-bottom: 4px; }
        .camp-org-tag { margin-top: 10px; padding: 6px 10px; border-radius: 8px; background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.08); font-size: 11px; color: rgba(255,255,255,0.5); display: flex; align-items: center; gap: 6px; }
        .camp-org-tag strong { color: #c084fc; }
        .camp-verified { font-size: 10px; color: #4ade80; margin-left: auto; }
        .no-camps { text-align: center; padding: 30px; color: rgba(255,255,255,0.2); font-size: 13px; }
        .orgs-section { }
        .org-count { font-size: 13px; color: rgba(255,255,255,0.3); margin-bottom: 16px; }
        .org-count span { color: #a855f7; font-weight: 600; }
        .org-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(300px, 1fr)); gap: 16px; }
        .org-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08); border-radius: 18px; padding: 22px; transition: all 0.2s; position: relative; overflow: hidden; }
        .org-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 2px; background: linear-gradient(90deg, #9333ea, #ec4899); opacity: 0; transition: opacity 0.2s; }
        .org-card:hover { border-color: rgba(168,85,247,0.3); transform: translateY(-3px); box-shadow: 0 8px 28px rgba(0,0,0,0.3); }
        .org-card:hover::before { opacity: 1; }
        .org-card-top { display: flex; align-items: center; gap: 14px; margin-bottom: 16px; }
        .org-avatar { width: 44px; height: 44px; border-radius: 12px; flex-shrink: 0; background: linear-gradient(135deg, #9333ea, #ec4899); display: flex; align-items: center; justify-content: center; font-size: 20px; }
        .org-name { font-family: 'Syne', sans-serif; font-size: 15px; font-weight: 700; color: #fff; margin-bottom: 2px; }
        .org-badge { display: inline-block; padding: 2px 8px; border-radius: 6px; font-size: 10px; font-weight: 600; background: rgba(34,197,94,0.12); color: #4ade80; }
        .org-divider { height: 1px; background: rgba(255,255,255,0.06); margin-bottom: 14px; }
        .org-detail { display: flex; align-items: flex-start; gap: 10px; margin-bottom: 10px; }
        .org-detail-icon { font-size: 14px; flex-shrink: 0; margin-top: 1px; }
        .org-detail-text { font-size: 13px; color: rgba(255,255,255,0.5); line-height: 1.4; }
        .org-detail-text a { color: #c084fc; text-decoration: none; }
        .org-detail-text a:hover { color: #f0abfc; }
        .org-camps-label { font-size: 11px; font-weight: 600; color: rgba(255,255,255,0.3); text-transform: uppercase; letter-spacing: 0.8px; margin: 14px 0 8px; }
        .org-camp-pill { display: flex; align-items: flex-start; gap: 8px; padding: 10px 12px; border-radius: 10px; margin-bottom: 8px; background: rgba(168,85,247,0.08); border: 1px solid rgba(168,85,247,0.18); transition: border-color 0.2s; }
        .org-camp-pill:hover { border-color: rgba(168,85,247,0.4); }
        .org-camp-pill-icon { font-size: 14px; flex-shrink: 0; margin-top: 1px; }
        .org-camp-pill-name { font-size: 13px; font-weight: 600; color: rgba(255,255,255,0.8); margin-bottom: 2px; }
        .org-camp-pill-detail { font-size: 11px; color: rgba(255,255,255,0.35); }
        .org-no-camps { font-size: 12px; color: rgba(255,255,255,0.2); padding: 10px 0; }
        .org-copy-btn { width: 100%; margin-top: 14px; padding: 10px; border-radius: 11px; border: 1px solid rgba(168,85,247,0.3); background: rgba(168,85,247,0.1); color: #c084fc; font-size: 13px; font-weight: 600; font-family: 'DM Sans', sans-serif; cursor: pointer; transition: all 0.2s; }
        .org-copy-btn:hover { background: rgba(168,85,247,0.2); }
        .org-empty { text-align: center; padding: 80px 20px; }
        .org-empty-icon { font-size: 48px; margin-bottom: 12px; }
        .org-empty-text { font-size: 15px; color: rgba(255,255,255,0.3); }
      `}</style>

      <div className="org-page">
        <div className="org-title">
          Blood Banks & <span>Organisations</span> 🏢
        </div>
        <div className="org-subtitle">
          Find a blood bank or camp near you — all verified on HemoLink
        </div>

        <input
          className="org-search"
          type="text"
          placeholder="🔍  Search by name or address..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        {/* ALL ACTIVE CAMPS */}
        <div className="all-camps-section">
          <div className="section-title">🏕️ Active Blood Donation Camps</div>
          <div className="section-sub">
            All upcoming camps — each one is linked to a verified registered
            blood bank
          </div>
          {camps.length === 0 ? (
            <div className="no-camps">
              No active camps right now. Check back soon!
            </div>
          ) : (
            <div className="camps-grid">
              {camps.map((camp) => (
                <div className="camp-card" key={camp._id}>
                  <div className="camp-card-top">
                    <span className="camp-icon">🏕️</span>
                    <div className="camp-name">
                      {camp.campName}
                      <span className="camp-active-badge">Active</span>
                    </div>
                  </div>
                  <div className="camp-detail">📍 {camp.address}</div>
                  <div className="camp-detail">
                    📅 {moment(camp.date).format("DD MMM YYYY")} &nbsp; 🕐{" "}
                    {camp.time}
                  </div>
                  <div className="camp-org-tag">
                    🏥 Organised by:{" "}
                    <strong>
                      {camp.organisation?.organisationName || "—"}
                    </strong>
                    <span className="camp-verified">✅ Verified</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* ORG CARDS */}
        <div className="orgs-section">
          <div className="section-title">🏢 Registered Blood Banks</div>
          <div className="section-sub">
            Each blood bank shows their contact info and active camps
          </div>
          {filteredOrgs.length > 0 && (
            <div className="org-count">
              Showing <span>{filteredOrgs.length}</span> organisation
              {filteredOrgs.length !== 1 ? "s" : ""}
            </div>
          )}
          {filteredOrgs.length === 0 ? (
            <div className="org-empty">
              <div className="org-empty-icon">🏢</div>
              <div className="org-empty-text">
                {orgs.length === 0
                  ? "No organisations registered yet"
                  : "No results found"}
              </div>
            </div>
          ) : (
            <div className="org-grid">
              {filteredOrgs.map((org) => {
                const orgCamps = getCampsForOrg(org._id);
                return (
                  <div className="org-card" key={org._id}>
                    <div className="org-card-top">
                      <div className="org-avatar">🏥</div>
                      <div>
                        <div className="org-name">{org.organisationName}</div>
                        <span className="org-badge">Accepting Donations</span>
                      </div>
                    </div>
                    <div className="org-divider" />
                    {org.email && (
                      <div className="org-detail">
                        <span className="org-detail-icon">✉️</span>
                        <div className="org-detail-text">
                          <a href={`mailto:${org.email}`}>{org.email}</a>
                        </div>
                      </div>
                    )}
                    {org.phone && (
                      <div className="org-detail">
                        <span className="org-detail-icon">📞</span>
                        <div className="org-detail-text">{org.phone}</div>
                      </div>
                    )}
                    {org.address && (
                      <div className="org-detail">
                        <span className="org-detail-icon">📍</span>
                        <div className="org-detail-text">{org.address}</div>
                      </div>
                    )}
                    {org.website && (
                      <div className="org-detail">
                        <span className="org-detail-icon">🌐</span>
                        <div className="org-detail-text">
                          <a
                            href={org.website}
                            target="_blank"
                            rel="noreferrer"
                          >
                            {org.website}
                          </a>
                        </div>
                      </div>
                    )}
                    <div className="org-camps-label">
                      🏕️ Camps by this organisation
                    </div>
                    {orgCamps.length === 0 ? (
                      <div className="org-no-camps">
                        No active camps right now
                      </div>
                    ) : (
                      orgCamps.map((camp) => (
                        <div className="org-camp-pill" key={camp._id}>
                          <span className="org-camp-pill-icon">🏕️</span>
                          <div>
                            <div className="org-camp-pill-name">
                              {camp.campName}
                            </div>
                            <div className="org-camp-pill-detail">
                              📍 {camp.address} &nbsp;|&nbsp; 📅{" "}
                              {moment(camp.date).format("DD MMM")} at{" "}
                              {camp.time}
                            </div>
                          </div>
                        </div>
                      ))
                    )}
                    <button
                      className="org-copy-btn"
                      onClick={() => {
                        navigator.clipboard?.writeText(org.email);
                        alert(`${org.organisationName}'s email copied!`);
                      }}
                    >
                      📋 Copy Email
                    </button>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </Layout>
  );
};

export default OrganisationPage;
